import { useEffect, useMemo, useState } from 'react'
import { useAuth } from '@/store/auth'
import { getSettings, updateSettings, uploadImage } from '@/api/admin'
import type { MiniappSettings } from '@/api/types'
import CloudImage from '@/components/CloudImage'

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="grid gap-1">
      <span className="text-xs text-zinc-600">{label}</span>
      {children}
    </label>
  )
}

const inputCls =
  'h-10 w-full rounded-lg border border-zinc-200 bg-white px-3 text-sm text-zinc-900 outline-none focus:border-zinc-900'
const textareaCls =
  'h-24 w-full resize-none rounded-lg border border-zinc-200 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900'

function splitComma(v: string) {
  return String(v || '')
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean)
}

function splitLines(v: string) {
  return String(v || '')
    .split(/\r?\n/)
    .map((s) => s.trim())
    .filter(Boolean)
}

export default function Settings() {
  const token = useAuth((s) => s.token)
  const [settings, setSettings] = useState<MiniappSettings | null>(null)
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState(false)
  const [uploading, setUploading] = useState(false)
  const [error, setError] = useState('')
  const [uploadError, setUploadError] = useState('')

  const [hotCaseIdsText, setHotCaseIdsText] = useState('')
  const [caseFiltersText, setCaseFiltersText] = useState('')
  const [honorsText, setHonorsText] = useState('')

  async function refresh() {
    if (!token) return
    setError('')
    setLoading(true)
    try {
      const r = await getSettings(token)
      setSettings(r)
    } catch (e) {
      setError(e instanceof Error ? e.message : '加载失败')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    refresh()
  }, [token])

  useEffect(() => {
    if (!settings) return
    setHotCaseIdsText((settings.home?.hotCaseIds || []).join(','))
    setCaseFiltersText((settings.cases?.filters || []).join(','))
    setHonorsText((settings.about?.honors || []).join('\n'))
  }, [settings?.updatedAt])

  const canSave = useMemo(() => Boolean(token && settings), [token, settings])

  async function save() {
    if (!token || !settings) return
    setSaving(true)
    setError('')
    try {
      const next: MiniappSettings = {
        ...settings,
        home: {
          ...settings.home,
          hotCaseIds: splitComma(hotCaseIdsText),
          cta: settings.home?.cta || { title: '', subtitle: '', buttonText: '' }
        },
        cases: {
          ...settings.cases,
          filters: splitComma(caseFiltersText)
        },
        about: {
          ...settings.about,
          honors: splitLines(honorsText),
          contact: settings.about?.contact || { address: '', phone: '', email: '' }
        }
      }
      const r = await updateSettings(token, {
        site: next.site,
        home: next.home,
        cases: next.cases,
        designers: next.designers,
        about: next.about,
        contact: next.contact
      })
      setSettings(r)
    } catch (e) {
      setError(e instanceof Error ? e.message : '保存失败')
    } finally {
      setSaving(false)
    }
  }

  async function onUpload(path: string, file: File) {
    if (!token || !settings) return
    setUploading(true)
    setUploadError('')
    try {
      const r = await uploadImage(token, file)
      const v = (r.cloudId || r.url) as string
      setSettings((s) => {
        if (!s) return s
        if (path === 'site.logoUrl') return { ...s, site: { ...s.site, logoUrl: v } }
        if (path === 'about.bannerUrl') return { ...s, about: { ...s.about, bannerUrl: v } }
        if (path === 'contact.mapImageUrl') return { ...s, contact: { ...s.contact, mapImageUrl: v } }
        if (path === 'contact.wechatQrUrl') return { ...s, contact: { ...s.contact, wechatQrUrl: v } }
        return s
      })
    } catch (e) {
      setUploadError(e instanceof Error ? e.message : '上传失败')
    } finally {
      setUploading(false)
    }
  }

  return (
    <div>
      <div className="flex items-end justify-between gap-3">
        <div>
          <div className="text-lg font-semibold text-zinc-900">基础设置</div>
          <div className="mt-1 text-sm text-zinc-500">全局信息与各页面基础字段维护（列表内容在“内容管理”里维护）</div>
        </div>
        <button
          type="button"
          disabled={!canSave || saving}
          className="inline-flex h-10 items-center justify-center rounded-lg bg-zinc-900 px-4 text-sm text-white hover:bg-zinc-800 disabled:opacity-60"
          onClick={save}
        >
          保存
        </button>
      </div>

      {error ? <div className="mt-4 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">{error}</div> : null}
      {uploadError ? (
        <div className="mt-3 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">{uploadError}</div>
      ) : null}

      <div className="mt-5 grid grid-cols-1 gap-4">
        <div className="rounded-2xl border border-zinc-200 bg-white p-5">
          <div className="text-sm font-semibold text-zinc-900">全局信息</div>
          <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
            <Field label="品牌名称">
              <input
                className={inputCls}
                value={settings?.site?.brandName || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, site: { ...s.site, brandName: e.target.value } } : s))}
              />
            </Field>
            <Field label="英文名">
              <input
                className={inputCls}
                value={settings?.site?.brandEn || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, site: { ...s.site, brandEn: e.target.value } } : s))}
              />
            </Field>
            <Field label="Slogan">
              <input
                className={inputCls}
                value={settings?.site?.slogan || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, site: { ...s.site, slogan: e.target.value } } : s))}
              />
            </Field>
            <Field label="客服电话">
              <input
                className={inputCls}
                value={settings?.site?.primaryPhone || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, site: { ...s.site, primaryPhone: e.target.value } } : s))}
              />
            </Field>
            <Field label="版权文案">
              <input
                className={inputCls}
                value={settings?.site?.copyrightText || ''}
                onChange={(e) =>
                  setSettings((s) => (s ? { ...s, site: { ...s.site, copyrightText: e.target.value } } : s))
                }
              />
            </Field>
            <div className="md:col-span-2">
              <div className="text-xs text-zinc-600">Logo</div>
              <div className="mt-2 flex items-center gap-3">
                {settings?.site?.logoUrl ? (
                  <CloudImage token={token || ''} src={settings.site.logoUrl} className="h-12 w-12 rounded-lg border border-zinc-200 object-cover" />
                ) : (
                  <div className="h-12 w-12 rounded-lg border border-zinc-200 bg-zinc-50" />
                )}
                <input
                  type="file"
                  accept="image/*"
                  disabled={uploading || loading}
                  className="block w-full text-sm text-zinc-700 file:mr-3 file:rounded-lg file:border-0 file:bg-zinc-900 file:px-3 file:py-2 file:text-sm file:text-white hover:file:bg-zinc-800 disabled:opacity-60"
                  onChange={(e) => {
                    const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                    if (f) onUpload('site.logoUrl', f)
                    e.currentTarget.value = ''
                  }}
                />
              </div>
              <div className="mt-3 text-xs text-zinc-600">Logo URL</div>
              <input
                className={inputCls}
                value={settings?.site?.logoUrl || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, site: { ...s.site, logoUrl: e.target.value } } : s))}
              />
            </div>
          </div>
        </div>

        <div className="rounded-2xl border border-zinc-200 bg-white p-5">
          <div className="text-sm font-semibold text-zinc-900">首页设置</div>
          <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
            <Field label="热门案例 ID（逗号分隔）">
              <input className={inputCls} value={hotCaseIdsText} onChange={(e) => setHotCaseIdsText(e.target.value)} />
            </Field>
            <div />
            <Field label="预约按钮标题">
              <input
                className={inputCls}
                value={settings?.home?.cta?.title || ''}
                onChange={(e) =>
                  setSettings((s) =>
                    s
                      ? { ...s, home: { ...s.home, cta: { ...(s.home.cta || { title: '', subtitle: '', buttonText: '' }), title: e.target.value } } }
                      : s
                  )
                }
              />
            </Field>
            <Field label="预约按钮副标题">
              <input
                className={inputCls}
                value={settings?.home?.cta?.subtitle || ''}
                onChange={(e) =>
                  setSettings((s) =>
                    s
                      ? {
                          ...s,
                          home: { ...s.home, cta: { ...(s.home.cta || { title: '', subtitle: '', buttonText: '' }), subtitle: e.target.value } }
                        }
                      : s
                  )
                }
              />
            </Field>
            <Field label="预约按钮文字">
              <input
                className={inputCls}
                value={settings?.home?.cta?.buttonText || ''}
                onChange={(e) =>
                  setSettings((s) =>
                    s
                      ? {
                          ...s,
                          home: {
                            ...s.home,
                            cta: { ...(s.home.cta || { title: '', subtitle: '', buttonText: '' }), buttonText: e.target.value }
                          }
                        }
                      : s
                  )
                }
              />
            </Field>
          </div>
          <div className="mt-3 text-xs text-zinc-500">首页轮播/导航/品质定制/品牌优势 请在「内容管理」里分别维护。</div>
        </div>

        <div className="rounded-2xl border border-zinc-200 bg-white p-5">
          <div className="text-sm font-semibold text-zinc-900">案例设置</div>
          <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
            <Field label="筛选标签（逗号分隔）">
              <input className={inputCls} value={caseFiltersText} onChange={(e) => setCaseFiltersText(e.target.value)} />
            </Field>
          </div>
        </div>

        <div className="rounded-2xl border border-zinc-200 bg-white p-5">
          <div className="text-sm font-semibold text-zinc-900">设计师设置</div>
          <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
            <Field label="页面顶部文案">
              <input
                className={inputCls}
                value={settings?.designers?.introText || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, designers: { ...s.designers, introText: e.target.value } } : s))}
              />
            </Field>
          </div>
        </div>

        <div className="rounded-2xl border border-zinc-200 bg-white p-5">
          <div className="text-sm font-semibold text-zinc-900">关于设置</div>
          <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
            <div className="md:col-span-2">
              <div className="text-xs text-zinc-600">Banner</div>
              <div className="mt-2 flex items-center gap-3">
                {settings?.about?.bannerUrl ? (
                  <CloudImage token={token || ''} src={settings.about.bannerUrl} className="h-12 w-12 rounded-lg border border-zinc-200 object-cover" />
                ) : (
                  <div className="h-12 w-12 rounded-lg border border-zinc-200 bg-zinc-50" />
                )}
                <input
                  type="file"
                  accept="image/*"
                  disabled={uploading || loading}
                  className="block w-full text-sm text-zinc-700 file:mr-3 file:rounded-lg file:border-0 file:bg-zinc-900 file:px-3 file:py-2 file:text-sm file:text-white hover:file:bg-zinc-800 disabled:opacity-60"
                  onChange={(e) => {
                    const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                    if (f) onUpload('about.bannerUrl', f)
                    e.currentTarget.value = ''
                  }}
                />
              </div>
              <div className="mt-3 text-xs text-zinc-600">Banner URL</div>
              <input
                className={inputCls}
                value={settings?.about?.bannerUrl || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, about: { ...s.about, bannerUrl: e.target.value } } : s))}
              />
            </div>
            <Field label="品牌名称">
              <input
                className={inputCls}
                value={settings?.about?.brandName || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, about: { ...s.about, brandName: e.target.value } } : s))}
              />
            </Field>
            <Field label="品牌口号">
              <input
                className={inputCls}
                value={settings?.about?.brandSlogan || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, about: { ...s.about, brandSlogan: e.target.value } } : s))}
              />
            </Field>
            <div className="md:col-span-2">
              <Field label="介绍文案">
                <textarea
                  className={textareaCls}
                  value={settings?.about?.introText || ''}
                  onChange={(e) => setSettings((s) => (s ? { ...s, about: { ...s.about, introText: e.target.value } } : s))}
                />
              </Field>
            </div>
            <div className="md:col-span-2">
              <Field label="荣誉资质（每行一条）">
                <textarea className={textareaCls} value={honorsText} onChange={(e) => setHonorsText(e.target.value)} />
              </Field>
            </div>
            <Field label="联系地址">
              <input
                className={inputCls}
                value={settings?.about?.contact?.address || ''}
                onChange={(e) =>
                  setSettings((s) =>
                    s
                      ? { ...s, about: { ...s.about, contact: { ...(s.about.contact || { address: '', phone: '', email: '' }), address: e.target.value } } }
                      : s
                  )
                }
              />
            </Field>
            <Field label="联系电话">
              <input
                className={inputCls}
                value={settings?.about?.contact?.phone || ''}
                onChange={(e) =>
                  setSettings((s) =>
                    s
                      ? { ...s, about: { ...s.about, contact: { ...(s.about.contact || { address: '', phone: '', email: '' }), phone: e.target.value } } }
                      : s
                  )
                }
              />
            </Field>
            <Field label="联系邮箱">
              <input
                className={inputCls}
                value={settings?.about?.contact?.email || ''}
                onChange={(e) =>
                  setSettings((s) =>
                    s
                      ? { ...s, about: { ...s.about, contact: { ...(s.about.contact || { address: '', phone: '', email: '' }), email: e.target.value } } }
                      : s
                  )
                }
              />
            </Field>
          </div>
          <div className="mt-3 text-xs text-zinc-500">关于页“优势块/发展历程”请在「内容管理」里分别维护。</div>
        </div>

        <div className="rounded-2xl border border-zinc-200 bg-white p-5">
          <div className="text-sm font-semibold text-zinc-900">联系设置</div>
          <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
            <div className="md:col-span-2">
              <div className="text-xs text-zinc-600">地图图</div>
              <div className="mt-2 flex items-center gap-3">
                {settings?.contact?.mapImageUrl ? (
                  <CloudImage token={token || ''} src={settings.contact.mapImageUrl} className="h-12 w-12 rounded-lg border border-zinc-200 object-cover" />
                ) : (
                  <div className="h-12 w-12 rounded-lg border border-zinc-200 bg-zinc-50" />
                )}
                <input
                  type="file"
                  accept="image/*"
                  disabled={uploading || loading}
                  className="block w-full text-sm text-zinc-700 file:mr-3 file:rounded-lg file:border-0 file:bg-zinc-900 file:px-3 file:py-2 file:text-sm file:text-white hover:file:bg-zinc-800 disabled:opacity-60"
                  onChange={(e) => {
                    const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                    if (f) onUpload('contact.mapImageUrl', f)
                    e.currentTarget.value = ''
                  }}
                />
              </div>
              <div className="mt-3 text-xs text-zinc-600">地图图 URL</div>
              <input
                className={inputCls}
                value={settings?.contact?.mapImageUrl || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, contact: { ...s.contact, mapImageUrl: e.target.value } } : s))}
              />
            </div>

            <Field label="地址">
              <input
                className={inputCls}
                value={settings?.contact?.address || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, contact: { ...s.contact, address: e.target.value } } : s))}
              />
            </Field>
            <Field label="电话">
              <input
                className={inputCls}
                value={settings?.contact?.phone || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, contact: { ...s.contact, phone: e.target.value } } : s))}
              />
            </Field>
            <Field label="邮箱">
              <input
                className={inputCls}
                value={settings?.contact?.email || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, contact: { ...s.contact, email: e.target.value } } : s))}
              />
            </Field>
            <Field label="官网">
              <input
                className={inputCls}
                value={settings?.contact?.website || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, contact: { ...s.contact, website: e.target.value } } : s))}
              />
            </Field>
            <div className="md:col-span-2">
              <div className="text-xs text-zinc-600">公众号二维码</div>
              <div className="mt-2 flex items-center gap-3">
                {settings?.contact?.wechatQrUrl ? (
                  <CloudImage token={token || ''} src={settings.contact.wechatQrUrl} className="h-12 w-12 rounded-lg border border-zinc-200 object-cover" />
                ) : (
                  <div className="h-12 w-12 rounded-lg border border-zinc-200 bg-zinc-50" />
                )}
                <input
                  type="file"
                  accept="image/*"
                  disabled={uploading || loading}
                  className="block w-full text-sm text-zinc-700 file:mr-3 file:rounded-lg file:border-0 file:bg-zinc-900 file:px-3 file:py-2 file:text-sm file:text-white hover:file:bg-zinc-800 disabled:opacity-60"
                  onChange={(e) => {
                    const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                    if (f) onUpload('contact.wechatQrUrl', f)
                    e.currentTarget.value = ''
                  }}
                />
              </div>
              <div className="mt-3 text-xs text-zinc-600">二维码 URL</div>
              <input
                className={inputCls}
                value={settings?.contact?.wechatQrUrl || ''}
                onChange={(e) => setSettings((s) => (s ? { ...s, contact: { ...s.contact, wechatQrUrl: e.target.value } } : s))}
              />
            </div>
          </div>
        </div>
      </div>

      <div className="mt-5 text-xs text-zinc-500">{loading ? '加载中...' : settings ? `更新时间：${settings.updatedAt}` : ''}</div>
    </div>
  )
}
