import type {
  AboutHistory,
  AboutInfo,
  CaseItem,
  ContentType,
  DesignerItem,
  HomeAdvantage,
  HomeBanner,
  HomeNav,
  HomeService
} from '@/api/types'
import Modal from '@/components/Modal'
import { uploadImage } from '@/api/admin'
import { useAuth } from '@/store/auth'
import { useEffect, useMemo, useState } from 'react'

type AnyItem = HomeBanner | HomeNav | HomeService | HomeAdvantage | CaseItem | DesignerItem | AboutInfo | AboutHistory

type Draft = Record<string, string>

function initDraft(type: ContentType, editing: AnyItem | null): Draft {
  if (type === 'homeBanners') {
    const v = editing as HomeBanner | null
    return { title: v?.title || '', desc: v?.desc || '', imageUrl: v?.imageUrl || '' }
  }
  if (type === 'homeNavs') {
    const v = editing as HomeNav | null
    return { type: v?.type || '', name: v?.name || '', iconUrl: v?.iconUrl || '' }
  }
  if (type === 'homeServices') {
    const v = editing as HomeService | null
    return { name: v?.name || '', desc: v?.desc || '', imageUrl: v?.imageUrl || '' }
  }
  if (type === 'homeAdvantages') {
    const v = editing as HomeAdvantage | null
    return { title: v?.title || '', desc: v?.desc || '' }
  }
  if (type === 'cases') {
    const v = editing as CaseItem | null
    return {
      title: v?.title || '',
      style: v?.style || '',
      area: v?.area || '',
      room: v?.room || '',
      desc: v?.desc || '',
      coverUrl: v?.coverUrl || ''
    }
  }
  if (type === 'designers') {
    const v = editing as DesignerItem | null
    return {
      name: v?.name || '',
      level: v?.level || '',
      tags: (v?.tags || []).join(','),
      desc: v?.desc || '',
      cases: typeof v?.cases === 'number' ? String(v?.cases) : '',
      years: typeof v?.years === 'number' ? String(v?.years) : '',
      like: typeof v?.like === 'number' ? String(v?.like) : '',
      avatarUrl: v?.avatarUrl || ''
    }
  }
  if (type === 'aboutInfos') {
    const v = editing as AboutInfo | null
    return { icon: v?.icon || '🏭', title: v?.title || '', desc: v?.desc || '' }
  }
  const v = editing as AboutHistory | null
  return { year: v?.year || '', event: v?.event || '' }
}

function parseTags(v: string) {
  return String(v || '')
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean)
}

function buildPayload(type: ContentType, draft: Draft) {
  const payload: Record<string, unknown> = {}
  if (type === 'homeBanners') {
    payload.title = draft.title || ''
    payload.desc = draft.desc || ''
    payload.imageUrl = draft.imageUrl || ''
  }
  if (type === 'homeNavs') {
    payload.type = draft.type || ''
    payload.name = draft.name || ''
    payload.iconUrl = draft.iconUrl || ''
  }
  if (type === 'homeServices') {
    payload.name = draft.name || ''
    payload.desc = draft.desc || ''
    payload.imageUrl = draft.imageUrl || ''
  }
  if (type === 'homeAdvantages') {
    payload.title = draft.title || ''
    payload.desc = draft.desc || ''
  }
  if (type === 'cases') {
    payload.title = draft.title || ''
    payload.style = draft.style || ''
    payload.area = draft.area || ''
    payload.room = draft.room || ''
    payload.desc = draft.desc || ''
    payload.coverUrl = draft.coverUrl || ''
  }
  if (type === 'designers') {
    payload.name = draft.name || ''
    payload.level = draft.level || ''
    payload.tags = parseTags(draft.tags || '')
    payload.desc = draft.desc || ''
    payload.cases = draft.cases === '' ? 0 : Number(draft.cases)
    payload.years = draft.years === '' ? 0 : Number(draft.years)
    payload.like = draft.like === '' ? 0 : Number(draft.like)
    payload.avatarUrl = draft.avatarUrl || ''
  }
  if (type === 'aboutInfos') {
    payload.icon = draft.icon || ''
    payload.title = draft.title || ''
    payload.desc = draft.desc || ''
  }
  if (type === 'aboutHistory') {
    payload.year = draft.year || ''
    payload.event = draft.event || ''
  }
  return payload
}

export default function ContentEditorModal({
  open,
  type,
  title,
  editing,
  error,
  onClose,
  onSave
}: {
  open: boolean
  type: ContentType
  title: string
  editing: AnyItem | null
  error: string
  onClose: () => void
  onSave: (payload: unknown) => Promise<void>
}) {
  const token = useAuth((s) => s.token)
  const initial = useMemo(() => initDraft(type, editing), [type, editing])
  const [draft, setDraft] = useState<Draft>(initial)
  const [uploading, setUploading] = useState(false)
  const [uploadError, setUploadError] = useState('')

  useEffect(() => {
    setDraft(initial)
    setUploadError('')
  }, [initial])

  async function onUpload(field: string, file: File) {
    if (!token) return
    setUploading(true)
    setUploadError('')
    try {
      const r = await uploadImage(token, file)
      setDraft((d) => ({ ...d, [field]: (r.cloudId || r.url) as string }))
    } catch (e) {
      setUploadError(e instanceof Error ? e.message : '上传失败')
    } finally {
      setUploading(false)
    }
  }

  const inputCls = 'mt-2 w-full rounded-lg border border-zinc-200 px-3 py-2 text-sm outline-none focus:border-zinc-400'
  const textareaCls = 'mt-2 h-20 w-full resize-none rounded-lg border border-zinc-200 px-3 py-2 text-sm outline-none focus:border-zinc-400'
  const uploadCls =
    'mt-2 block w-full text-sm text-zinc-700 file:mr-3 file:rounded-lg file:border-0 file:bg-zinc-900 file:px-3 file:py-2 file:text-sm file:text-white hover:file:bg-zinc-800 disabled:opacity-60'

  return (
    <Modal open={open} title={editing ? `编辑${title}` : `新建${title}`} onClose={onClose}>
      <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
        {type === 'homeBanners' ? (
          <>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">标题</div>
              <input className={inputCls} value={draft.title || ''} onChange={(e) => setDraft((d) => ({ ...d, title: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">描述</div>
              <textarea className={textareaCls} value={draft.desc || ''} onChange={(e) => setDraft((d) => ({ ...d, desc: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">图片</div>
              <input
                type="file"
                accept="image/*"
                disabled={uploading}
                className={uploadCls}
                onChange={(e) => {
                  const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                  if (f) onUpload('imageUrl', f)
                  e.currentTarget.value = ''
                }}
              />
              <div className="mt-3 text-xs font-medium text-zinc-700">图片 URL</div>
              <input className={inputCls} value={draft.imageUrl || ''} onChange={(e) => setDraft((d) => ({ ...d, imageUrl: e.target.value }))} />
            </div>
          </>
        ) : null}

        {type === 'homeNavs' ? (
          <>
            <div>
              <div className="text-xs font-medium text-zinc-700">type</div>
              <input className={inputCls} value={draft.type || ''} onChange={(e) => setDraft((d) => ({ ...d, type: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">名称</div>
              <input className={inputCls} value={draft.name || ''} onChange={(e) => setDraft((d) => ({ ...d, name: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">图标</div>
              <input
                type="file"
                accept="image/*"
                disabled={uploading}
                className={uploadCls}
                onChange={(e) => {
                  const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                  if (f) onUpload('iconUrl', f)
                  e.currentTarget.value = ''
                }}
              />
              <div className="mt-3 text-xs font-medium text-zinc-700">图标 URL</div>
              <input className={inputCls} value={draft.iconUrl || ''} onChange={(e) => setDraft((d) => ({ ...d, iconUrl: e.target.value }))} />
            </div>
          </>
        ) : null}

        {type === 'homeServices' ? (
          <>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">名称</div>
              <input className={inputCls} value={draft.name || ''} onChange={(e) => setDraft((d) => ({ ...d, name: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">描述</div>
              <textarea className={textareaCls} value={draft.desc || ''} onChange={(e) => setDraft((d) => ({ ...d, desc: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">图片</div>
              <input
                type="file"
                accept="image/*"
                disabled={uploading}
                className={uploadCls}
                onChange={(e) => {
                  const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                  if (f) onUpload('imageUrl', f)
                  e.currentTarget.value = ''
                }}
              />
              <div className="mt-3 text-xs font-medium text-zinc-700">图片 URL</div>
              <input className={inputCls} value={draft.imageUrl || ''} onChange={(e) => setDraft((d) => ({ ...d, imageUrl: e.target.value }))} />
            </div>
          </>
        ) : null}

        {type === 'homeAdvantages' ? (
          <>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">标题</div>
              <input className={inputCls} value={draft.title || ''} onChange={(e) => setDraft((d) => ({ ...d, title: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">描述</div>
              <textarea className={textareaCls} value={draft.desc || ''} onChange={(e) => setDraft((d) => ({ ...d, desc: e.target.value }))} />
            </div>
          </>
        ) : null}

        {type === 'cases' ? (
          <>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">标题</div>
              <input className={inputCls} value={draft.title || ''} onChange={(e) => setDraft((d) => ({ ...d, title: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">风格</div>
              <input className={inputCls} value={draft.style || ''} onChange={(e) => setDraft((d) => ({ ...d, style: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">面积</div>
              <input className={inputCls} value={draft.area || ''} onChange={(e) => setDraft((d) => ({ ...d, area: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">户型</div>
              <input className={inputCls} value={draft.room || ''} onChange={(e) => setDraft((d) => ({ ...d, room: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">封面</div>
              <input
                type="file"
                accept="image/*"
                disabled={uploading}
                className={uploadCls}
                onChange={(e) => {
                  const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                  if (f) onUpload('coverUrl', f)
                  e.currentTarget.value = ''
                }}
              />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">封面 URL</div>
              <input className={inputCls} value={draft.coverUrl || ''} onChange={(e) => setDraft((d) => ({ ...d, coverUrl: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">简介</div>
              <textarea className={textareaCls} value={draft.desc || ''} onChange={(e) => setDraft((d) => ({ ...d, desc: e.target.value }))} />
            </div>
          </>
        ) : null}

        {type === 'designers' ? (
          <>
            <div>
              <div className="text-xs font-medium text-zinc-700">姓名</div>
              <input className={inputCls} value={draft.name || ''} onChange={(e) => setDraft((d) => ({ ...d, name: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">职位</div>
              <input className={inputCls} value={draft.level || ''} onChange={(e) => setDraft((d) => ({ ...d, level: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">标签（逗号分隔）</div>
              <input className={inputCls} value={draft.tags || ''} onChange={(e) => setDraft((d) => ({ ...d, tags: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">简介</div>
              <textarea className={textareaCls} value={draft.desc || ''} onChange={(e) => setDraft((d) => ({ ...d, desc: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">案例数</div>
              <input className={inputCls} value={draft.cases || ''} onChange={(e) => setDraft((d) => ({ ...d, cases: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">年经验</div>
              <input className={inputCls} value={draft.years || ''} onChange={(e) => setDraft((d) => ({ ...d, years: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">好评率</div>
              <input className={inputCls} value={draft.like || ''} onChange={(e) => setDraft((d) => ({ ...d, like: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">头像</div>
              <input
                type="file"
                accept="image/*"
                disabled={uploading}
                className={uploadCls}
                onChange={(e) => {
                  const f = e.target.files && e.target.files[0] ? e.target.files[0] : null
                  if (f) onUpload('avatarUrl', f)
                  e.currentTarget.value = ''
                }}
              />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">头像 URL</div>
              <input className={inputCls} value={draft.avatarUrl || ''} onChange={(e) => setDraft((d) => ({ ...d, avatarUrl: e.target.value }))} />
            </div>
          </>
        ) : null}

        {type === 'aboutInfos' ? (
          <>
            <div>
              <div className="text-xs font-medium text-zinc-700">图标</div>
              <input className={inputCls} value={draft.icon || ''} onChange={(e) => setDraft((d) => ({ ...d, icon: e.target.value }))} />
            </div>
            <div>
              <div className="text-xs font-medium text-zinc-700">标题</div>
              <input className={inputCls} value={draft.title || ''} onChange={(e) => setDraft((d) => ({ ...d, title: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">描述</div>
              <textarea className={textareaCls} value={draft.desc || ''} onChange={(e) => setDraft((d) => ({ ...d, desc: e.target.value }))} />
            </div>
          </>
        ) : null}

        {type === 'aboutHistory' ? (
          <>
            <div>
              <div className="text-xs font-medium text-zinc-700">年份</div>
              <input className={inputCls} value={draft.year || ''} onChange={(e) => setDraft((d) => ({ ...d, year: e.target.value }))} />
            </div>
            <div className="md:col-span-2">
              <div className="text-xs font-medium text-zinc-700">事件</div>
              <input className={inputCls} value={draft.event || ''} onChange={(e) => setDraft((d) => ({ ...d, event: e.target.value }))} />
            </div>
          </>
        ) : null}
      </div>

      {error || uploadError ? (
        <div className="mt-4 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700">{error || uploadError}</div>
      ) : null}

      <div className="mt-5 flex items-center justify-end gap-2">
        <button type="button" className="rounded-lg border border-zinc-200 bg-white px-4 py-2 text-sm text-zinc-700 hover:bg-zinc-50" onClick={onClose}>
          取消
        </button>
        <button
          type="button"
          className="rounded-lg bg-zinc-900 px-4 py-2 text-sm text-white hover:bg-zinc-800"
          disabled={uploading}
          onClick={() => onSave(buildPayload(type, draft))}
        >
          保存
        </button>
      </div>
    </Modal>
  )
}
