import type { ContentType } from '@/api/types'
import { cn } from '@/lib/utils'

function Tab({ active, label, onClick }: { active: boolean; label: string; onClick: () => void }) {
  return (
    <button
      type="button"
      className={cn(
        'rounded-lg px-3 py-2 text-sm',
        active ? 'bg-zinc-900 text-white' : 'border border-zinc-200 bg-white text-zinc-700 hover:bg-zinc-50'
      )}
      onClick={onClick}
    >
      {label}
    </button>
  )
}

export default function ContentTabs({ type, onChange }: { type: ContentType; onChange: (t: ContentType) => void }) {
  return (
    <div className="mt-5 flex flex-wrap gap-2">
      <Tab active={type === 'homeBanners'} label="首页轮播" onClick={() => onChange('homeBanners')} />
      <Tab active={type === 'homeNavs'} label="首页导航" onClick={() => onChange('homeNavs')} />
      <Tab active={type === 'homeServices'} label="品质定制" onClick={() => onChange('homeServices')} />
      <Tab active={type === 'homeAdvantages'} label="品牌优势" onClick={() => onChange('homeAdvantages')} />
      <Tab active={type === 'cases'} label="案例" onClick={() => onChange('cases')} />
      <Tab active={type === 'designers'} label="设计师" onClick={() => onChange('designers')} />
      <Tab active={type === 'aboutInfos'} label="关于-优势块" onClick={() => onChange('aboutInfos')} />
      <Tab active={type === 'aboutHistory'} label="关于-历程" onClick={() => onChange('aboutHistory')} />
    </div>
  )
}
