import type {
  AdminLoginReq,
  AdminLoginResp,
  AdminMe,
  AdminStats,
  ContentType,
  Paged,
  CaseItem,
  DesignerItem,
  HomeAdvantage,
  HomeBanner,
  HomeNav,
  HomeService,
  AboutInfo,
  AboutHistory,
  MiniappSettings,
  Lead,
  UploadResult
} from '@/api/types'
import { requestJson } from '@/api/http'

export function adminLogin(body: AdminLoginReq) {
  return requestJson<AdminLoginResp>('/api/admin/login', { method: 'POST', body })
}

export function adminMe(token: string) {
  return requestJson<AdminMe>('/api/admin/me', { token })
}

export function adminStats(token: string) {
  return requestJson<AdminStats>('/api/admin/stats', { token })
}

function contentEntity(type: ContentType) {
  if (type === 'homeBanners') return 'home-banners'
  if (type === 'homeNavs') return 'home-navs'
  if (type === 'homeServices') return 'home-services'
  if (type === 'homeAdvantages') return 'home-advantages'
  if (type === 'aboutInfos') return 'about-infos'
  if (type === 'aboutHistory') return 'about-history'
  return type
}

type AnyContent = HomeBanner | HomeNav | HomeService | HomeAdvantage | CaseItem | DesignerItem | AboutInfo | AboutHistory

export function listContent(token: string, type: ContentType, q: string, limit = 50, offset = 0) {
  const entity = contentEntity(type)
  return requestJson<Paged<AnyContent>>(`/api/admin/${entity}`, {
    token,
    query: { q, limit, offset }
  })
}

export function createContent(token: string, type: ContentType, payload: unknown) {
  const entity = contentEntity(type)
  return requestJson<AnyContent>(`/api/admin/${entity}`, {
    token,
    method: 'POST',
    body: payload
  })
}

export function updateContent(token: string, type: ContentType, id: string, payload: unknown) {
  const entity = contentEntity(type)
  return requestJson<AnyContent>(`/api/admin/${entity}/${id}`, {
    token,
    method: 'PUT',
    body: payload
  })
}

export function deleteContent(token: string, type: ContentType, id: string) {
  const entity = contentEntity(type)
  return requestJson<unknown>(`/api/admin/${entity}/${id}`, {
    token,
    method: 'DELETE'
  })
}

export function listLeads(token: string, q: string, limit = 50, offset = 0) {
  return requestJson<Paged<Lead>>('/api/admin/leads', { token, query: { q, limit, offset } })
}

export function getSettings(token: string) {
  return requestJson<MiniappSettings>('/api/admin/settings', { token })
}

export function updateSettings(token: string, payload: unknown) {
  return requestJson<MiniappSettings>('/api/admin/settings', { token, method: 'PUT', body: payload })
}

export async function uploadImage(token: string, file: File) {
  const form = new FormData()
  form.append('file', file)
  const res = await fetch('/api/admin/upload', {
    method: 'POST',
    headers: { authorization: `Bearer ${token}` },
    body: form
  })
  const text = await res.text()
  let data: any = null
  try {
    data = text ? JSON.parse(text) : null
  } catch (_e) {}
  if (!res.ok) throw new Error((data && data.message) || `HTTP ${res.status}`)
  if (!data || !data.ok) throw new Error((data && data.message) || '上传失败')
  return data.data as UploadResult
}

export async function getFileUrl(token: string, fileId: string) {
  const u = new URL('/api/admin/file-url', window.location.origin)
  u.searchParams.set('fileId', fileId)
  const res = await fetch(u.toString(), { headers: { authorization: `Bearer ${token}` } })
  const text = await res.text()
  let data: any = null
  try {
    data = text ? JSON.parse(text) : null
  } catch (_e) {}
  if (!res.ok) throw new Error((data && data.message) || `HTTP ${res.status}`)
  if (!data || !data.ok) throw new Error((data && data.message) || '获取失败')
  return (data.data && data.data.url) as string
}
