import type { ContentType } from '@/api/types'
import CloudImage from '@/components/CloudImage'
import { Pencil, Trash2 } from 'lucide-react'

type AnyItem = { id: string } & Record<string, unknown>

export default function ContentTable({
  type,
  items,
  loading,
  token,
  onEdit,
  onDelete
}: {
  type: ContentType
  items: AnyItem[]
  loading: boolean
  token: string
  onEdit: (item: AnyItem) => void
  onDelete: (id: string) => void
}) {
  const cols = ['内容', '说明', '预览', '操作']

  function leftText(it: AnyItem) {
    if (type === 'homeNavs') return String(it.name || '')
    if (type === 'homeServices') return String(it.name || '')
    if (type === 'homeAdvantages') return String(it.title || '')
    if (type === 'designers') return String(it.name || '')
    if (type === 'aboutInfos') return String(it.title || '')
    if (type === 'aboutHistory') return String(it.year || '')
    return String(it.title || '')
  }

  function midText(it: AnyItem) {
    if (type === 'homeBanners') return String(it.desc || '')
    if (type === 'homeNavs') return `type: ${String(it.type || '-')}`
    if (type === 'homeServices') return String(it.desc || '')
    if (type === 'homeAdvantages') return String(it.desc || '')
    if (type === 'cases') return `${String(it.style || '-')}${it.area ? ` · ${String(it.area)}` : ''}${it.room ? ` · ${String(it.room)}` : ''}`
    if (type === 'designers') return `${String(it.level || '-')}${Array.isArray(it.tags) && it.tags.length ? ` · ${it.tags.join(' / ')}` : ''}`
    if (type === 'aboutInfos') return String(it.desc || '')
    if (type === 'aboutHistory') return String(it.event || '')
    return ''
  }

  function previewUrl(it: AnyItem) {
    const raw =
      type === 'homeBanners'
        ? String(it.imageUrl || '')
        : type === 'homeNavs'
          ? String(it.iconUrl || '')
          : type === 'homeServices'
            ? String(it.imageUrl || '')
            : type === 'cases'
              ? String(it.coverUrl || '')
              : type === 'designers'
                ? String(it.avatarUrl || '')
                : ''
    if (raw.startsWith('cloud://')) return ''
    return raw
  }

  return (
    <div className="mt-4 overflow-hidden rounded-2xl border border-zinc-200 bg-white">
      <div className="grid grid-cols-12 gap-2 border-b border-zinc-200 px-4 py-3 text-xs font-medium text-zinc-500">
        <div className="col-span-5">{cols[0]}</div>
        <div className="col-span-4">{cols[1]}</div>
        <div className="col-span-1">{cols[2]}</div>
        <div className="col-span-2 text-right">{cols[3]}</div>
      </div>
      {loading ? (
        <div className="px-4 py-6 text-sm text-zinc-500">加载中...</div>
      ) : items.length ? (
        <div>
          {items.map((it) => {
            const left = leftText(it)
            const mid = midText(it)
            const url = previewUrl(it)
            return (
              <div key={it.id} className="grid grid-cols-12 items-center gap-2 px-4 py-3 text-sm hover:bg-zinc-50">
                <div className="col-span-5">
                  <div className="truncate font-medium text-zinc-900">{left}</div>
                  <div className="mt-1 truncate text-xs text-zinc-500">ID: {it.id}</div>
                </div>
                <div className="col-span-4 truncate text-zinc-700">{mid || '-'}</div>
                <div className="col-span-1">
                  {url ? (
                    <CloudImage token={token} src={url} className="h-10 w-10 rounded-lg border border-zinc-200 object-cover" />
                  ) : (
                    <div className="text-xs text-zinc-400">-</div>
                  )}
                </div>
                <div className="col-span-2 flex items-center justify-end gap-2">
                  <button
                    type="button"
                    className="inline-flex h-8 w-8 items-center justify-center rounded-md text-zinc-600 hover:bg-zinc-100"
                    onClick={() => onEdit(it)}
                  >
                    <Pencil className="h-4 w-4" />
                  </button>
                  <button
                    type="button"
                    className="inline-flex h-8 w-8 items-center justify-center rounded-md text-red-600 hover:bg-red-50"
                    onClick={() => onDelete(it.id)}
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                </div>
              </div>
            )
          })}
        </div>
      ) : (
        <div className="px-4 py-6 text-sm text-zinc-500">暂无数据</div>
      )}
    </div>
  )
}
